UPDATE J09D_temp
SET ENTSCHEIDUNG = (
  SELECT CASE WHEN COUNT(DISTINCT d2.EQUNR) < 3 THEN 'KSA' ELSE 'EVU' END
  FROM J09D_temp d2
  WHERE d2.HAUS = J09D_temp.HAUS
);

UPDATE J09D_work2
SET ENTSCHEIDUNG = 'MANDATORY_READING'
WHERE EQUNR IN (SELECT EQUNR FROM J09D_mandatory_eq);
